# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).
# Category: path_traversal

using Microsoft.AspNetCore.Http;
using System.IO;

public class FilesController : Controller
{
    [HttpGet]
    public IActionResult GetFile([FromRoute] string filename)
    {
        string uploadsFolder = Directory.GetCurrentDirectory() + @"\uploads\";
        string filePath = uploadsFolder + filename;

        if (System.IO.File.Exists(filePath))
        {
            IFileInfo fileInfo = new FileInfo(filePath);
            string contentType = GetContentType(fileInfo.Extension);

            return File(filePath, contentType);
        }

        throw new FileNotFoundException("File not found", filename);
    }

    private string GetContentType(string extension)
    {
        switch (extension.ToLower())
        {
            case ".txt":
                return "text/plain";
            case ".pdf":
                return "application/pdf";
            case ".jpg":
            case ".jpeg":
                return "image/jpeg";
            case ".png":
                return "image/png";
            default:
                return "application/octet-stream";
        }
    }
}